import 'package:fl_chart/fl_chart.dart';
import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import '../../repositories/providers.dart';
final statsProvider = StreamProvider((ref)=>ref.watch(adminRepositoryProvider).stats());
class DashboardScreen extends ConsumerWidget { const DashboardScreen({super.key}); @override Widget build(BuildContext context, WidgetRef ref)=>Scaffold(appBar: AppBar(title: const Text('Dashboard Realtime')), body: ref.watch(statsProvider).when(data:(s)=>ListView(padding: const EdgeInsets.all(24), children:[Wrap(spacing:16, runSpacing:16, children:s.entries.map((e)=>SizedBox(width:220, child: Card(child: Padding(padding: const EdgeInsets.all(20), child: Column(crossAxisAlignment: CrossAxisAlignment.start, children:[Text(e.key.toUpperCase()), Text('${e.value}', style: Theme.of(context).textTheme.headlineMedium?.copyWith(fontWeight: FontWeight.bold))]))))).toList()), const SizedBox(height:24), Card(child: Padding(padding: const EdgeInsets.all(20), child: SizedBox(height:260, child: BarChart(BarChartData(titlesData: const FlTitlesData(), barGroups: List.generate(6, (i)=>BarChartGroupData(x:i, barRods:[BarChartRodData(toY: (i+1) * (s['courts']!.toDouble()+1) / 6, color: const Color(0xFF0D9488))]))))))]), error:(e,_)=>Center(child:Text('$e')), loading:()=>const Center(child:CircularProgressIndicator()))); }
